    if (sellingPrice !== undefined) {
      const spCheck = validatePrice(sellingPrice, 'Prix de vente');
      if (!spCheck.valid) return res.status(400).json({ error: 'Erreur mise Ã  jour recette', details: spCheck.error });
    }
    if (laborCostPerHour != null) {
      const lCheck = validatePositiveNumber(laborCostPerHour, 'CoÃ»t main d\'oeuvre/h');
      if (!lCheck.valid) return res.status(400).json({ error: 'Erreur mise Ã  jour recette', details: lCheck.error });
    }
    const updated = await prisma.$transaction(async (tx) => {
      await tx.recipe.update({ where: { id: recipeId }, data: {
        name: safeName, category: safeCategory, sellingPrice: parseFloat(sellingPrice), nbPortions: parseInt(nbPortions) || 1,
