      };
      const mins = entry.totalMinutes || 0;
      existing.totalMinutes += mins;
      existing.totalCost += (mins / 60) * entry.employee.hourlyRate;
      existing.entryCount++;
      existing.days[entry.date] = (existing.days[entry.date] || 0) + mins;
