                            const updated = [...formIngredients];
                            updated[idx].quantity = e.target.value;
                            setFormIngredients(updated);
                          }}
                        />
                        <span className="text-xs text-[#9CA3AF] dark:text-[#737373] w-10">{unitLabel}</span>
                        <input
                          type="number"
                          step="1"
                          min="0"
                          max="100"
