                disabled={saving}
              >
                {saving ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> {t("recipes.saving")}</>
                ) : saveSuccess ? (
                  <><Check className="w-4 h-4" /> {t("recipes.saved")}</>
