                    <hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;">
                    <p style="font-size:11px;color:#94a3b8;margin:0;">EnvoyÃ© via RestauMargin â€” <a href="https://www.restaumargin.fr" style="color:#94a3b8;">restaumargin.fr</a></p>
                    <p style="font-size:11px;color:#94a3b8;margin:4px 0 0;">RÃ©pondez directement Ã  cet email pour continuer la conversation.</p>
                  </div>
                </div>
              `,
            });
            console.log(`[MESSAGE EMAIL] Sent to ${recipientEmail} for conversation ${req.params.id}`);
          }
        }
      }
    } catch (emailErr: any) {
