// View & filter state
const [viewMode, setViewMode] = useState<'grid' | 'table'>('grid');
const [activeTab, setActiveTab] = useState<'recipes' | 'templates'>('recipes');
const [templateCategoryFilter, setTemplateCategoryFilter] = useState<string>('all');
