  }

  async function handleClone(recipeId: number) {
    try {
      const cloned = await cloneRecipe(recipeId);
      showToast(t("recipes.recipeCloned"), 'success');
      loadData();
    } catch {
      showToast(t("recipes.errorCloning"), 'error');
